```cpp
void StudentProfile::validateData() {
    if (studentID <= 0) {
        throw std::invalid_argument("Student ID must be positive.");
    }
    if (gpa < 0.0 || gpa > 4.0) {
        throw std::domain_error("GPA must be between 0.0 and 4.0.");
    }
}
```

